{
  "title": "Vacancy Mirror \u2014 Scraper Dashboard",
  "uid": "scraper-dashboard",
  "tags": [
    "scraper",
    "vacancy-mirror"
  ],
  "timezone": "browser",
  "refresh": "30s",
  "time": {
    "from": "now-24h",
    "to": "now"
  },
  "panels": [
    {
      "id": 20,
      "title": "\ud83c\udf9b Scraper Control Panel",
      "type": "text",
      "gridPos": {
        "x": 0,
        "y": 0,
        "w": 24,
        "h": 24
      },
      "options": {
        "mode": "html",
        "content": "<style>*{box-sizing:border-box}#term{display:flex;flex-direction:column;height:calc(100% - 8px);background:#0d0d0d;border-radius:6px;overflow:hidden;font-family:'Courier New',monospace}#out{flex:1;overflow-y:auto;padding:10px 12px;font-size:12px;line-height:1.55;color:#d4d4d4;min-height:0;white-space:pre-wrap;word-break:break-word}#input-row{display:flex;align-items:center;padding:6px 10px;border-top:1px solid #222;background:#111}#prompt{color:#00e676;margin-right:6px;font-size:12px;white-space:nowrap}#cmd{flex:1;background:transparent;border:none;outline:none;color:#fff;font-family:'Courier New',monospace;font-size:12px;caret-color:#00e676}.g{color:#69f0ae}.r{color:#ef5350}.y{color:#ffa726}.b{color:#42a5f5}.d{color:#888}.w{color:#fff}.m{color:#ce93d8}</style><div id=\"term\"><div id=\"out\"></div><div id=\"input-row\"><span id=\"prompt\">scraper&gt;</span><input id=\"cmd\" autocomplete=\"off\" autocorrect=\"off\" spellcheck=\"false\" placeholder=\"type 'help' and press Enter\"></div></div><script>(function(){const API='http://127.0.0.1:8000';let KEY=localStorage.getItem('SCRAPER_API_KEY')||prompt('Enter SCRAPER_API_KEY for protected commands')||'';if(KEY){localStorage.setItem('SCRAPER_API_KEY',KEY);}const CAT_NAMES={'531770282580668418':'Web, Mobile & Software Dev','531770282580668420':'Data Science & Analytics','531770282580668421':'Design & Creative','531770282580668419':'IT & Networking','531770282580668422':'Sales & Marketing','531770282580668416':'Admin Support','531770282580668417':'Customer Service','531770282584862721':'Accounting & Consulting','531770282584862722':'Engineering & Architecture','531770282584862723':'Legal','531770282580668423':'Writing','531770282584862720':'Translation'};let state={step:null,jobsPage:1};let logTimer=null;let statusTimer=null;let prevStatus=null;let lastLogLen=0;const out=document.getElementById('out');const inp=document.getElementById('cmd');function esc(s){return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}function print(html){out.innerHTML+=html+'\\n';out.scrollTop=out.scrollHeight;}function printLine(cls,text){print('<span class=\"'+cls+'\">'+esc(text)+'</span>');}function sep(){print('<span class=\"d\">'+'─'.repeat(60)+'</span>');}function ready(){state={step:null,jobsPage:state.jobsPage||1};document.getElementById('prompt').textContent='scraper> ';}function showHelp(){sep();print('<span class=\"g\">  Chaos Scraper Console — Commands:</span>');print('<span class=\"w\">  status</span>            <span class=\"d\">— scraper API status (running/idle)</span>');print('<span class=\"w\">  chaos</span>             <span class=\"d\">— chaos state: progress per category</span>');print('<span class=\"w\">  start</span>             <span class=\"d\">— manually start chaos scraper session</span>');print('<span class=\"w\">  stop</span>              <span class=\"d\">— stop running scraper</span>');print('<span class=\"w\">  logs [N]</span>          <span class=\"d\">— show last N log lines (default 80)</span>');print('<span class=\"w\">  jobs [N]</span>          <span class=\"d\">— show last N jobs from DB (default 20)</span>');print('<span class=\"w\">  jobs more</span>         <span class=\"d\">— next page of jobs</span>');print('<span class=\"w\">  schedule</span>          <span class=\"d\">— show cron status</span>');print('<span class=\"w\">  schedule on</span>       <span class=\"d\">— enable cron (Mon–Sat 8–22)</span>');print('<span class=\"w\">  schedule off</span>      <span class=\"d\">— disable cron</span>');print('<span class=\"w\">  clear</span>             <span class=\"d\">— delete all jobs from DB (idle only)</span>');print('<span class=\"w\">  cls</span>               <span class=\"d\">— clear console output</span>');print('<span class=\"w\">  help</span>              <span class=\"d\">— this message</span>');sep();}function apiFetch(path,opts){return fetch(API+path,opts).then(r=>{if(!r.ok)return r.json().then(e=>{throw new Error(e.detail||r.status);});return r.json();});}function startLogPoll(){stopLogPoll();lastLogLen=0;logTimer=setInterval(pollLogs,4000);}function stopLogPoll(){if(logTimer){clearInterval(logTimer);logTimer=null;}}function pollLogs(){apiFetch('/logs?lines=150').then(d=>{const lines=d.lines||[];const atBottom=out.scrollHeight-out.scrollTop-out.clientHeight<80;if(lines.length>lastLogLen){const fresh=lines.slice(lastLogLen);lastLogLen=lines.length;fresh.forEach(l=>{const cls=l.includes('Ban/Cloudflare')||l.includes('ERROR')?'r':l.includes('WARNING')?'y':'g';print('<span class=\"'+cls+'\">'+esc(l)+'</span>');});if(atBottom)out.scrollTop=out.scrollHeight;}}).catch(()=>{});}function startStatusPoll(){if(statusTimer)return;statusTimer=setInterval(()=>{apiFetch('/status').then(d=>{if(prevStatus==='running'&&d.status==='idle'){stopLogPoll();lastLogLen=0;sep();printLine('g','✅ Scraper session finished — status: IDLE');sep();}prevStatus=d.status;}).catch(()=>{});},5000);}function cmdStatus(){apiFetch('/status').then(d=>{sep();const s=d.status;if(s==='running'){print('<span class=\"b\">   Status  : <span class=\"w\">RUNNING</span></span>');print('<span class=\"d\">  Started  : <span class=\"w\">'+(d.started_at||'—')+'</span></span>');print('<span class=\"d\">  Watching logs automatically...</span>');startLogPoll();}else{print('<span class=\"g\">  ✅ Status  : <span class=\"w\">IDLE</span></span>');}sep();}).catch(e=>printLine('r','Error: '+e.message)).finally(()=>ready());}function cmdChaos(){apiFetch('/chaos-state').then(d=>{sep();print('<span class=\"g\">  Chaos Scraper — Weekly Progress (target: '+d.target_per_cat+' per category)</span>');sep();const cats=d.categories||[];const total=cats.reduce((a,c)=>a+c.collected,0);cats.sort((a,b)=>b.collected-a.collected);cats.forEach(c=>{const pct=Math.min(100,Math.round(c.collected/d.target_per_cat*100));const bar='█'.repeat(Math.round(pct/5))+'░'.repeat(20-Math.round(pct/5));const col=pct>=100?'g':pct>=50?'b':'y';const name=(c.name||c.uid).slice(0,30).padEnd(30);print('  <span class=\"d\">'+esc(name)+'</span> <span class=\"'+col+'\">'+bar+'</span> <span class=\"w\">'+c.collected+'</span><span class=\"d\">/'+d.target_per_cat+' ('+pct+'%)</span>  <span class=\"d\">'+c.visited_pages+' pages visited</span>');});sep();print('<span class=\"d\">  Total in DB: <span class=\"w\">'+total+'</span>  |  State file: <span class=\"w\">'+(d.state_file||'chaos_state.json')+'</span></span>');if(d.reset_day)print('<span class=\"d\">  Resets every: <span class=\"w\">Monday</span></span>');sep();}).catch(e=>{printLine('y','  /chaos-state not available — showing DB count only');apiFetch('/jobs?page=1&page_size=1').then(d=>printLine('d','  Total jobs in DB: '+d.total)).catch(()=>{});}).finally(()=>ready());}function cmdLogs(arg){const n=parseInt(arg)||80;apiFetch('/logs?lines='+n).then(d=>{const lines=d.lines||[];sep();if(!lines.length){printLine('d','  (log buffer is empty)');sep();ready();return;}lines.forEach(l=>{const cls=l.includes('Ban/Cloudflare')||l.includes('ERROR')?'r':l.includes('WARNING')||l.includes('ban')?'y':'g';print('<span class=\"'+cls+'\">'+esc(l)+'</span>');});sep();printLine('d','  '+lines.length+' lines shown.');ready();}).catch(e=>{printLine('r','Error: '+e.message);ready();});}function cmdJobs(arg){const n=(!arg||arg==='more')?20:parseInt(arg)||20;if(arg==='more')state.jobsPage++;else state.jobsPage=1;const offset=(state.jobsPage-1)*n;apiFetch('/jobs?page='+state.jobsPage+'&page_size='+n).then(d=>{sep();print('<span class=\"g\">  Jobs in DB: <span class=\"w\">'+d.total+'</span>  — showing '+(offset+1)+'–'+Math.min(offset+n,d.total)+'  (page '+state.jobsPage+'/'+d.pages+')</span>');print('<span class=\"d\">  #    Title                                    Country      Budget      Date</span>');print('<span class=\"d\">  '+'─'.repeat(78)+'</span>');d.jobs.forEach((j,i)=>{const title=(j.title||'').slice(0,40).padEnd(40);const country=(j.client_country||'—').slice(0,10).padEnd(12);const budget=j.hourly_budget_min?('$'+j.hourly_budget_min+'–$'+(j.hourly_budget_max||'?')+'/h').padEnd(12):(j.weekly_budget?('$'+j.weekly_budget+'/w').padEnd(12):'  —         ');const date=(j.published_at||j.scraped_at||'').slice(0,10);print('<span class=\"d\">  '+(offset+i+1)+'. </span><span class=\"w\">'+esc(title)+'</span><span class=\"d\"> '+esc(country)+esc(budget)+' '+esc(date)+'</span>');});sep();if(state.jobsPage<d.pages)printLine('d','  Type \"jobs more\" for next page.');ready();}).catch(e=>{printLine('r','Error: '+e.message);ready();});}function cmdStop(){apiFetch('/stop',{method:'POST',headers:{'X-API-Key':KEY}}).then(d=>printLine(d.ok?'g':'y',(d.ok?'⏹ ':'⚠ ')+d.message)).catch(e=>printLine('r','Error: '+e.message)).finally(()=>ready());}function cmdStart(){apiFetch('/status').then(d=>{if(d.status==='running'){printLine('y','⚠ Scraper already running. Use \"stop\" first.');ready();return;}printLine('d','  Launching chaos scraper session...');return apiFetch('/scrape-chaos',{method:'POST',headers:{'X-API-Key':KEY}});}).then(d=>{if(!d)return;printLine('g','▶ '+d.message);printLine('d','  Cycles all 12 categories, max 50 min session.');printLine('d','  Use \"logs\" to watch progress, \"stop\" to abort.');startLogPoll();}).catch(e=>printLine('r','Error: '+e.message)).finally(()=>ready());}function cmdSchedule(arg){if(!arg){apiFetch('/schedule').then(d=>{sep();const en=d.enabled;print('<span class=\"d\">  Cron schedule: <span class=\"'+(en?'g':'r')+'\">'+(en?'ENABLED':'DISABLED')+'</span></span>');if(d.jobs&&d.jobs.length){const j=d.jobs[0];print('<span class=\"d\">  Schedule     : <span class=\"w\">'+esc(j.minute)+' '+esc(j.hour)+' '+esc(j.dom)+' '+esc(j.month)+' '+esc(j.dow)+'</span></span>');}sep();printLine('d','  schedule on  — enable cron');printLine('d','  schedule off — disable cron');sep();}).catch(e=>printLine('r','Error: '+e.message)).finally(()=>ready());return;}if(arg==='on'){apiFetch('/schedule/enable',{method:'POST',headers:{'X-API-Key':KEY}}).then(d=>printLine('g','✅ '+d.message)).catch(e=>{if(e.message.includes('404')||e.message.includes('No disabled')){return apiFetch('/schedule',{method:'POST',headers:{'Content-Type':'application/json','X-API-Key':KEY},body:JSON.stringify({minute:'0',hour:'8-22',dom:'*',month:'*',dow:'1-6',enabled:true})}).then(d=>printLine('g','✅ Cron schedule set and enabled.'));}throw e;}).catch(e=>printLine('r','Error: '+e.message)).finally(()=>ready());}else if(arg==='off'){apiFetch('/schedule/disable',{method:'POST',headers:{'X-API-Key':KEY}}).then(d=>printLine('y','⏸ '+d.message)).catch(e=>printLine('r','Error: '+e.message)).finally(()=>ready());}else{printLine('r','Usage: schedule | schedule on | schedule off');ready();}}function cmdClear(){apiFetch('/status').then(d=>{if(d.status==='running'){printLine('r','Cannot clear DB while running. Stop first.');ready();return;}printLine('y','⚠ This will delete ALL jobs from DB. Type YES to confirm:');state.step='clear_confirm';document.getElementById('prompt').textContent='confirm> ';}).catch(e=>{printLine('r','Error: '+e.message);ready();});}function handleStep(val){if(state.step==='clear_confirm'){state.step=null;document.getElementById('prompt').textContent='scraper> ';if(val.trim()==='YES'){apiFetch('/jobs/clear',{method:'POST',headers:{'X-API-Key':KEY}}).then(r=>printLine('g',' Deleted '+r.deleted_rows+' rows.')).catch(e=>printLine('r','Error: '+e.message)).finally(()=>ready());}else{printLine('d','Cancelled.');ready();}return;}}inp.addEventListener('keydown',function(e){if(e.key!=='Enter')return;const raw=inp.value.trim();inp.value='';if(!raw)return;print('<span class=\"m\">'+esc(document.getElementById('prompt').textContent)+'</span><span class=\"w\">'+esc(raw)+'</span>');if(state.step){handleStep(raw);return;}const parts=raw.trim().split(/\\s+/);const cmd=parts[0].toLowerCase();const arg=parts[1]||'';if(cmd==='help'||cmd==='?'){showHelp();}else if(cmd==='status'){cmdStatus();}else if(cmd==='chaos'||cmd==='progress'||cmd==='state'){cmdChaos();}else if(cmd==='start'||cmd==='run'){cmdStart();}else if(cmd==='stop'){cmdStop();}else if(cmd==='logs'){cmdLogs(arg);}else if(cmd==='jobs'){cmdJobs(arg);}else if(cmd==='schedule'){cmdSchedule(arg);}else if(cmd==='clear'){cmdClear();}else if(cmd==='cls'){out.innerHTML='';printLine('d','Console cleared.');}else{printLine('r','Unknown: '+esc(raw)+'. Type \"help\".');}});print('<span class=\"g\">  Vacancy Mirror — Chaos Scraper Console</span>');print('<span class=\"d\">  Type <span class=\"w\">help</span> for commands  |  <span class=\"w\">chaos</span> — weekly progress  |  <span class=\"w\">logs</span> — live log</span>');sep();apiFetch('/status').then(d=>{prevStatus=d.status;const s=d.status;const col=s==='running'?'b':'g';print('<span class=\"d\">  API connected. Status: <span class=\"'+col+'\">'+esc(s)+'</span></span>');if(s==='running'){print('<span class=\"d\">  Attaching log stream...</span>');startLogPoll();}startStatusPoll();}).catch(()=>printLine('r','  ⚠ Cannot reach scraper-api at '+API));})();</script>"
      }
    },
    {
      "id": 1,
      "title": "Total Jobs in DB",
      "type": "stat",
      "gridPos": {
        "x": 0,
        "y": 24,
        "w": 6,
        "h": 4
      },
      "datasource": {
        "type": "grafana-postgresql-datasource",
        "uid": "PCC52D03280B7034C"
      },
      "targets": [
        {
          "datasource": {
            "type": "grafana-postgresql-datasource",
            "uid": "PCC52D03280B7034C"
          },
          "rawSql": "SELECT COUNT(*) AS total FROM raw_jobs",
          "format": "table",
          "refId": "A"
        }
      ],
      "options": {
        "colorMode": "background",
        "graphMode": "none",
        "textMode": "value"
      },
      "fieldConfig": {
        "defaults": {
          "color": { "mode": "fixed", "fixedColor": "green" }
        }
      }
    },
    {
      "id": 2,
      "title": "Jobs Added Last 1h",
      "type": "stat",
      "gridPos": {
        "x": 6,
        "y": 24,
        "w": 6,
        "h": 4
      },
      "datasource": {
        "type": "grafana-postgresql-datasource",
        "uid": "PCC52D03280B7034C"
      },
      "targets": [
        {
          "datasource": {
            "type": "grafana-postgresql-datasource",
            "uid": "PCC52D03280B7034C"
          },
          "rawSql": "SELECT COUNT(*) FROM raw_jobs WHERE scraped_at > NOW() - INTERVAL '1 hour'",
          "format": "table",
          "refId": "A"
        }
      ],
      "options": {
        "colorMode": "background",
        "graphMode": "none"
      },
      "fieldConfig": {
        "defaults": {
          "color": { "mode": "fixed", "fixedColor": "blue" }
        }
      }
    },
    {
      "id": 3,
      "title": "Jobs Added Today",
      "type": "stat",
      "gridPos": {
        "x": 12,
        "y": 24,
        "w": 4,
        "h": 4
      },
      "datasource": {
        "type": "grafana-postgresql-datasource",
        "uid": "PCC52D03280B7034C"
      },
      "targets": [
        {
          "datasource": {
            "type": "grafana-postgresql-datasource",
            "uid": "PCC52D03280B7034C"
          },
          "rawSql": "SELECT COUNT(*) FROM raw_jobs WHERE scraped_at::date = CURRENT_DATE",
          "format": "table",
          "refId": "A"
        }
      ],
      "options": {
        "colorMode": "none",
        "graphMode": "none"
      }
    },
    {
      "id": 13,
      "title": "Scrape Speed (/jh)",
      "type": "stat",
      "gridPos": {
        "x": 16,
        "y": 24,
        "w": 8,
        "h": 4
      },
      "datasource": {
        "type": "grafana-postgresql-datasource",
        "uid": "PCC52D03280B7034C"
      },
      "targets": [
        {
          "datasource": {
            "type": "grafana-postgresql-datasource",
            "uid": "PCC52D03280B7034C"
          },
          "rawSql": "WITH hourly AS ( SELECT date_trunc('hour', scraped_at) AS h, COUNT(*)::numeric AS jobs FROM raw_jobs WHERE scraped_at > NOW() - INTERVAL '24 hours' GROUP BY 1 ), agg AS ( SELECT COALESCE(SUM(jobs), 0)::numeric AS total_jobs, COALESCE(COUNT(*) FILTER (WHERE jobs > 0), 0)::numeric AS active_hours FROM hourly ) SELECT ROUND(CASE WHEN active_hours > 0 THEN total_jobs / active_hours ELSE 0 END, 1) AS speed_n_jh FROM agg",
          "format": "table",
          "refId": "A"
        }
      ],
      "options": {
        "colorMode": "background",
        "graphMode": "none",
        "textMode": "value"
      },
      "fieldConfig": {
        "defaults": {
          "unit": "suffix:/jh",
          "color": {
            "mode": "thresholds"
          },
          "thresholds": {
            "mode": "absolute",
            "steps": [
              { "color": "red", "value": null },
              { "color": "orange", "value": 50 },
              { "color": "green", "value": 120 }
            ]
          }
        }
      }
    },
    {
      "id": 5,
      "title": "Jobs Scraped per Hour (last 24h)",
      "type": "timeseries",
      "gridPos": {
        "x": 0,
        "y": 28,
        "w": 12,
        "h": 16
      },
      "datasource": {
        "type": "grafana-postgresql-datasource",
        "uid": "PCC52D03280B7034C"
      },
      "targets": [
        {
          "datasource": {
            "type": "grafana-postgresql-datasource",
            "uid": "PCC52D03280B7034C"
          },
          "rawSql": "SELECT date_trunc('hour', scraped_at) AS time, COUNT(*) AS jobs FROM raw_jobs WHERE scraped_at > NOW() - INTERVAL '24 hours' GROUP BY 1 ORDER BY 1",
          "format": "time_series",
          "refId": "A"
        }
      ],
      "fieldConfig": {
        "defaults": {
          "color": { "mode": "fixed", "fixedColor": "green" },
          "custom": { "fillOpacity": 20 }
        }
      },
      "options": {
        "legend": { "displayMode": "hidden" }
      }
    },
    {
      "id": 6,
      "title": "Jobs per Category (total)",
      "type": "barchart",
      "gridPos": {
        "x": 12,
        "y": 28,
        "w": 12,
        "h": 16
      },
      "datasource": {
        "type": "grafana-postgresql-datasource",
        "uid": "PCC52D03280B7034C"
      },
      "targets": [
        {
          "datasource": {
            "type": "grafana-postgresql-datasource",
            "uid": "PCC52D03280B7034C"
          },
          "rawSql": "WITH categories AS ( SELECT DISTINCT category_uid, category_name FROM scrape_runs ), counts AS ( SELECT category_uid, COUNT(*) AS jobs FROM raw_jobs GROUP BY category_uid ) SELECT CASE categories.category_name WHEN 'Web, Mobile & Software Dev' THEN 'WebDev' WHEN 'Data Science & Analytics' THEN 'Data' WHEN 'Design & Creative' THEN 'Design' WHEN 'IT & Networking' THEN 'IT' WHEN 'Sales & Marketing' THEN 'Sales' WHEN 'Admin Support' THEN 'Admin' WHEN 'Customer Service' THEN 'Support' WHEN 'Accounting & Consulting' THEN 'Acct' WHEN 'Engineering & Architecture' THEN 'Eng' WHEN 'Legal' THEN 'Legal' WHEN 'Writing' THEN 'Writing' WHEN 'Translation' THEN 'Transl' ELSE categories.category_name END AS category, COALESCE(counts.jobs, 0) AS jobs FROM categories LEFT JOIN counts ON counts.category_uid = categories.category_uid ORDER BY jobs DESC",
          "format": "table",
          "refId": "A"
        }
      ],
      "fieldConfig": {
        "defaults": {
          "color": { "mode": "fixed", "fixedColor": "blue" },
          "custom": {
            "axisPlacement": "auto",
            "axisLabel": "Category",
            "axisSoftMin": 0,
            "showValue": "always"
          }
        }
      },
      "options": {
        "xField": "category",
        "orientation": "vertical",
        "xTickLabelRotation": -90,
        "xTickLabelSpacing": 0,
        "legend": {
          "displayMode": "hidden"
        }
      }
    },
    {
      "id": 7,
      "title": "Residential Proxy Usage (MB/h, real)",
      "type": "timeseries",
      "gridPos": {
        "x": 0,
        "y": 44,
        "w": 12,
        "h": 8
      },
      "datasource": {
        "type": "grafana-postgresql-datasource",
        "uid": "PCC52D03280B7034C"
      },
      "targets": [
        {
          "datasource": {
            "type": "grafana-postgresql-datasource",
            "uid": "PCC52D03280B7034C"
          },
          "rawSql": "WITH bounds AS ( SELECT to_timestamp($__unixEpochFrom())::timestamptz AS from_ts, to_timestamp($__unixEpochTo())::timestamptz AS to_ts ), hours AS ( SELECT generate_series( date_trunc('hour', (SELECT from_ts FROM bounds)) - INTERVAL '1 hour', date_trunc('hour', (SELECT to_ts FROM bounds)), INTERVAL '1 hour' ) AS time ), snapshots AS ( SELECT date_trunc('hour', captured_at) AS time, MAX(bytes_used) AS bytes_used FROM proxy_usage_snapshots WHERE provider = 'webshare' AND bytes_used IS NOT NULL AND captured_at <= (SELECT to_ts FROM bounds) GROUP BY 1 ), joined AS ( SELECT h.time, s.bytes_used FROM hours h LEFT JOIN snapshots s USING (time) ), filled AS ( SELECT time, MAX(bytes_used) OVER ( ORDER BY time ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW ) AS bytes_filled FROM joined ), deltas AS ( SELECT time, GREATEST( bytes_filled - LAG(bytes_filled) OVER (ORDER BY time), 0 ) AS delta_bytes FROM filled ) SELECT time, ROUND((COALESCE(delta_bytes, 0) / 1048576.0)::numeric, 2) AS mb_per_hour FROM deltas WHERE time >= date_trunc('hour', (SELECT from_ts FROM bounds)) ORDER BY 1",
          "format": "time_series",
          "refId": "A"
        }
      ],
      "fieldConfig": {
        "defaults": {
          "unit": "suffix:MB/h",
          "color": { "mode": "fixed", "fixedColor": "orange" },
          "custom": { "fillOpacity": 16 }
        }
      },
      "options": {
        "legend": { "displayMode": "hidden" }
      }
    },
    {
      "id": 14,
      "title": " Category Scraping Progress",
      "type": "text",
      "gridPos": {
        "x": 0,
        "y": 52,
        "w": 24,
        "h": 14
      },
      "options": {
        "mode": "html",
        "content": "<style>*{box-sizing:border-box}#cat-wrap{height:100%;overflow-y:auto;background:#0d0d0d;border-radius:6px;padding:10px 14px;font-family:'Courier New',monospace;color:#d4d4d4}#cat-wrap h3{margin:0 0 8px;font-size:13px;color:#69f0ae;letter-spacing:.04em}table{width:100%;border-collapse:collapse;font-size:11.5px}th{text-align:left;color:#888;font-weight:normal;padding:3px 6px;border-bottom:1px solid #222;white-space:nowrap}td{padding:3px 6px;vertical-align:middle;white-space:nowrap}.bar-cell{width:160px}.bar-bg{background:#1e1e1e;border-radius:3px;height:10px;width:160px;overflow:hidden}.bar-fill{height:10px;border-radius:3px;transition:width .4s}.pages-pill{display:inline-block;background:#1a2a1a;border:1px solid #2a4a2a;border-radius:10px;padding:1px 7px;font-size:10px;color:#69f0ae;margin-right:3px}.pages-visited{color:#42a5f5;font-size:10px}.upwork-total{color:#888;font-size:10px}.pct-num{color:#fff;font-weight:bold;min-width:38px;display:inline-block;text-align:right}.cat-name{color:#e0e0e0;max-width:180px;overflow:hidden;text-overflow:ellipsis}.good{color:#69f0ae}.mid{color:#ffa726}.low{color:#ef5350}#footer{margin-top:8px;color:#555;font-size:10px;text-align:right}#last-update{color:#444;font-size:10px}</style><div id=\"cat-wrap\"><h3>Category Scraping Progress <span id=\"last-update\"></span></h3><table><thead><tr><th>#</th><th>Category</th><th>Upwork jobs</th><th>Max pages</th><th>Pages visited</th><th style=\"width:160px\">Collected / Target</th><th>%</th><th>Collectable</th></tr></thead><tbody id=\"cat-tbody\"><tr><td colspan=\"8\" style=\"color:#555;padding:20px;text-align:center\">Loading...</td></tr></tbody></table><div id=\"footer\">Auto-refresh every 30s</div></div><script>(function(){const API='http://127.0.0.1:8000';const PER_PAGE=50;function barColor(pct){return pct>=100?'#69f0ae':pct>=50?'#42a5f5':pct>=20?'#ffa726':'#ef5350';}function fmtNum(n){if(!n&&n!==0)return'-';return n.toLocaleString();}function render(d){const cats=d.categories||[];const target=d.target_per_cat||5000;cats.sort((a,b)=>b.collected-a.collected);const tbody=document.getElementById('cat-tbody');tbody.innerHTML='';cats.forEach((c,i)=>{const upworkJobs=c.total_upwork_jobs||0;const realMax=c.real_max_page||0;const visitedPages=c.visited_pages||0;const coldStart=(upworkJobs===0&&realMax===0&&visitedPages===0);const shownCollected=coldStart?0:(c.collected||0);const pct=Math.min(100,Math.round(shownCollected/target*100));const col=barColor(pct);const pctCls=pct>=100?'good':pct>=50?'mid':'low';const maxPages=realMax?Math.min(realMax,100):('-');const maxCollect=(c.max_collectable||0)>0?fmtNum(c.max_collectable):'-';const visitedList=(c.visited_pages_list||[]).slice(0,8).join(', ')+(c.visited_pages_list&&c.visited_pages_list.length>8?'…':'');const tr=document.createElement('tr');tr.innerHTML='<td style=\"color:#555\">'+(i+1)+'</td>'+'<td class=\"cat-name\">'+(c.name||c.uid)+'</td>'+'<td class=\"upwork-total\">'+fmtNum(upworkJobs)+'</td>'+'<td style=\"color:#ce93d8\">'+maxPages+'</td>'+'<td><span class=\"pages-visited\">'+visitedPages+' pages</span>'+(visitedList?'<br><span style=\"color:#444;font-size:9px\">'+visitedList+'</span>':'')+'</td>'+'<td class=\"bar-cell\"><div class=\"bar-bg\"><div class=\"bar-fill\" style=\"width:'+pct+'%;background:'+col+'\"></div></div></td>'+'<td><span class=\"pct-num '+pctCls+'\">'+pct+'%</span> <span style=\"color:#555;font-size:10px\">'+shownCollected+'/'+target+'</span></td>'+'<td style=\"color:#888;font-size:10px\">'+maxCollect+'</td>';tbody.appendChild(tr);});document.getElementById('last-update').textContent='— updated '+new Date().toLocaleTimeString();}function load(){fetch(API+'/chaos-state').then(r=>r.json()).then(d=>{render(d);}).catch(e=>{document.getElementById('cat-tbody').innerHTML='<tr><td colspan=\"8\" style=\"color:#ef5350;padding:10px\">Error: '+e.message+'</td></tr>';});}load();setInterval(load,30000);})();</script>"
      }
