          "rawSql": "SELECT date_trunc('hour', started_at) AS time, COUNT(*) AS done FROM scrape_runs WHERE status = 'done' AND started_at > NOW() - INTERVAL '7 days' GROUP BY 1 ORDER BY 1",
          "format": "time_series",
          "refId": "A"
