      },
      "targets": [
        {
          "datasource": {
            "type": "grafana-postgresql-datasource",
            "uid": "PCC52D03280B7034C"
          },
          "rawSql": "WITH hourly AS ( SELECT date_trunc('hour', scraped_at) AS h, COUNT(*)::numeric AS jobs FROM raw_jobs WHERE scraped_at > NOW() - INTERVAL '24 hours' GROUP BY 1 ), agg AS ( SELECT COALESCE(SUM(jobs), 0)::numeric AS total_jobs, COALESCE(COUNT(*) FILTER (WHERE jobs > 0), 0)::numeric AS active_hours FROM hourly ) SELECT ROUND(CASE WHEN active_hours > 0 THEN total_jobs / active_hours ELSE 0 END, 1) AS speed_n_jh FROM agg",
          "format": "table",
          "refId": "A"
        }
      ],
      "options": {
        "colorMode": "background",
        "graphMode": "none",
        "textMode": "value"
      },
