          "rawSql": "WITH categories AS ( SELECT DISTINCT category_uid, category_name FROM scrape_runs ), counts AS ( SELECT category_uid, COUNT(*) AS jobs FROM raw_jobs GROUP BY category_uid ) SELECT categories.category_name AS category, COALESCE(counts.jobs, 0) AS jobs FROM categories LEFT JOIN counts ON counts.category_uid = categories.category_uid ORDER BY jobs DESC",
