    {
      "id": 14,
      "title": " Category Scraping Progress",
      "type": "text",
      "gridPos": {
        "x": 0,
        "y": 52,
        "w": 24,
        "h": 14
      },
      "options": {
        "mode": "html",
        "content": "<style>*{box-sizing:border-box}#cat-wrap{height:100%;overflow-y:auto;background:#0d0d0d;border-radius:6px;padding:10px 14px;font-family:'Courier New',monospace;color:#d4d4d4}#cat-wrap h3{margin:0 0 8px;font-size:13px;color:#69f0ae;letter-spacing:.04em}table{width:100%;border-collapse:collapse;font-size:11.5px}th{text-align:left;color:#888;font-weight:normal;padding:3px 6px;border-bottom:1px solid #222;white-space:nowrap}td{padding:3px 6px;vertical-align:middle;white-space:nowrap}.bar-cell{width:160px}.bar-bg{background:#1e1e1e;border-radius:3px;height:10px;width:160px;overflow:hidden}.bar-fill{height:10px;border-radius:3px;transition:width .4s}.pages-pill{display:inline-block;background:#1a2a1a;border:1px solid #2a4a2a;border-radius:10px;padding:1px 7px;font-size:10px;color:#69f0ae;margin-right:3px}.pages-visited{color:#42a5f5;font-size:10px}.upwork-total{color:#888;font-size:10px}.pct-num{color:#fff;font-weight:bold;min-width:38px;display:inline-block;text-align:right}.cat-name{color:#e0e0e0;max-width:180px;overflow:hidden;text-overflow:ellipsis}.good{color:#69f0ae}.mid{color:#ffa726}.low{color:#ef5350}#footer{margin-top:8px;color:#555;font-size:10px;text-align:right}#last-update{color:#444;font-size:10px}</style><div id=\"cat-wrap\"><h3>Category Scraping Progress <span id=\"last-update\"></span></h3><table><thead><tr><th>#</th><th>Category</th><th>Upwork jobs</th><th>Max pages</th><th>Pages visited</th><th style=\"width:160px\">Collected / Target</th><th>%</th><th>Collectable</th></tr></thead><tbody id=\"cat-tbody\"><tr><td colspan=\"8\" style=\"color:#555;padding:20px;text-align:center\">Loading...</td></tr></tbody></table><div id=\"footer\">Auto-refresh every 30s</div></div><script>(function(){const API='http://127.0.0.1:8000';const PER_PAGE=50;function barColor(pct){return pct>=100?'#69f0ae':pct>=50?'#42a5f5':pct>=20?'#ffa726':'#ef5350';}function fmtNum(n){if(!n&&n!==0)return'-';return n.toLocaleString();}function render(d){const cats=d.categories||[];const target=d.target_per_cat||5000;cats.sort((a,b)=>b.collected-a.collected);const tbody=document.getElementById('cat-tbody');tbody.innerHTML='';cats.forEach((c,i)=>{const upworkJobs=c.total_upwork_jobs||0;const realMax=c.real_max_page||0;const visitedPages=c.visited_pages||0;const coldStart=(upworkJobs===0&&realMax===0&&visitedPages===0);const shownCollected=coldStart?0:(c.collected||0);const pct=Math.min(100,Math.round(shownCollected/target*100));const col=barColor(pct);const pctCls=pct>=100?'good':pct>=50?'mid':'low';const maxPages=realMax?Math.min(realMax,100):('-');const maxCollect=(c.max_collectable||0)>0?fmtNum(c.max_collectable):'-';const visitedList=(c.visited_pages_list||[]).slice(0,8).join(', ')+(c.visited_pages_list&&c.visited_pages_list.length>8?'…':'');const tr=document.createElement('tr');tr.innerHTML='<td style=\"color:#555\">'+(i+1)+'</td>'+'<td class=\"cat-name\">'+(c.name||c.uid)+'</td>'+'<td class=\"upwork-total\">'+fmtNum(upworkJobs)+'</td>'+'<td style=\"color:#ce93d8\">'+maxPages+'</td>'+'<td><span class=\"pages-visited\">'+visitedPages+' pages</span>'+(visitedList?'<br><span style=\"color:#444;font-size:9px\">'+visitedList+'</span>':'')+'</td>'+'<td class=\"bar-cell\"><div class=\"bar-bg\"><div class=\"bar-fill\" style=\"width:'+pct+'%;background:'+col+'\"></div></div></td>'+'<td><span class=\"pct-num '+pctCls+'\">'+pct+'%</span> <span style=\"color:#555;font-size:10px\">'+shownCollected+'/'+target+'</span></td>'+'<td style=\"color:#888;font-size:10px\">'+maxCollect+'</td>';tbody.appendChild(tr);});document.getElementById('last-update').textContent='— updated '+new Date().toLocaleTimeString();}function load(){fetch(API+'/chaos-state').then(r=>r.json()).then(d=>{render(d);}).catch(e=>{document.getElementById('cat-tbody').innerHTML='<tr><td colspan=\"8\" style=\"color:#ef5350;padding:10px\">Error: '+e.message+'</td></tr>';});}load();setInterval(load,30000);})();</script>"
      }
    },
    {
      "id": 8,
      "title": "Server CPU Usage %",
      "type": "timeseries",
      "gridPos": {
        "x": 0,
        "y": 66,
        "w": 12,
        "h": 8
      },
      "datasource": {
        "type": "prometheus",
        "uid": "PBFA97CFB590B2093"
      },
      "targets": [
        {
          "datasource": {
            "type": "prometheus",
            "uid": "PBFA97CFB590B2093"
          },
          "expr": "100 - (avg(rate(node_cpu_seconds_total{mode=\"idle\"}[5m])) * 100)",
          "legendFormat": "CPU %",
          "refId": "A"
        }
      ],
      "fieldConfig": {
        "defaults": {
          "unit": "percent",
          "min": 0,
          "max": 100,
          "color": {
            "mode": "fixed",
            "fixedColor": "blue"
          }
        }
      }
    },
    {
      "id": 9,
      "title": "Server RAM Usage %",
      "type": "timeseries",
      "gridPos": {
        "x": 12,
        "y": 66,
        "w": 12,
        "h": 8
      },
      "datasource": {
        "type": "prometheus",
        "uid": "PBFA97CFB590B2093"
      },
      "targets": [
        {
          "datasource": {
            "type": "prometheus",
            "uid": "PBFA97CFB590B2093"
          },
          "expr": "(1 - (node_memory_MemAvailable_bytes / node_memory_MemTotal_bytes)) * 100",
          "legendFormat": "RAM %",
          "refId": "A"
        }
      ],
      "fieldConfig": {
        "defaults": {
          "unit": "percent",
          "min": 0,
          "max": 100,
          "color": {
            "mode": "fixed",
            "fixedColor": "purple"
          }
        }
      }
    },
    {
      "id": 10,
      "title": "Total Jobs in DB",
      "type": "stat",
      "gridPos": {
        "x": 0,
        "y": 74,
        "w": 8,
        "h": 4
      },
      "datasource": {
        "type": "grafana-postgresql-datasource",
        "uid": "PCC52D03280B7034C"
      },
      "targets": [
        {
          "datasource": {
            "type": "grafana-postgresql-datasource",
            "uid": "PCC52D03280B7034C"
          },
          "rawSql": "SELECT COUNT(*) AS total FROM raw_jobs",
          "format": "table",
          "refId": "A"
        }
      ],
      "options": {
        "colorMode": "none",
        "graphMode": "none"
      }
    },
    {
      "id": 11,
      "title": "Jobs Added Last 7 days",
      "type": "stat",
      "gridPos": {
        "x": 8,
        "y": 74,
        "w": 8,
        "h": 4
      },
      "datasource": {
        "type": "grafana-postgresql-datasource",
        "uid": "PCC52D03280B7034C"
      },
      "targets": [
        {
          "datasource": {
            "type": "grafana-postgresql-datasource",
            "uid": "PCC52D03280B7034C"
          },
          "rawSql": "SELECT COUNT(*) FROM raw_jobs WHERE scraped_at > NOW() - INTERVAL '7 days'",
          "format": "table",
          "refId": "A"
        }
      ],
      "options": {
        "colorMode": "background",
        "graphMode": "none"
      },
      "fieldConfig": {
        "defaults": {
          "color": { "mode": "fixed", "fixedColor": "blue" }
        }
      }
    },
    {
      "id": 12,
      "title": "Categories Scraped Today",
      "type": "stat",
      "gridPos": {
        "x": 16,
        "y": 74,
        "w": 8,
        "h": 4
      },
      "datasource": {
        "type": "grafana-postgresql-datasource",
        "uid": "PCC52D03280B7034C"
      },
      "targets": [
        {
          "datasource": {
            "type": "grafana-postgresql-datasource",
            "uid": "PCC52D03280B7034C"
          },
          "rawSql": "SELECT COUNT(DISTINCT category_uid) FROM raw_jobs WHERE scraped_at::date = CURRENT_DATE",
          "format": "table",
          "refId": "A"
        }
      ],
      "options": {
        "colorMode": "none",
        "graphMode": "none"
      }
    },
    {
      "id": 21,
      "title": "Last Successful Scrape",
      "description": "Seconds since the last scrape_run with status='done'. Green <2h, orange <6h, red >6h.",
      "type": "stat",
      "gridPos": { "x": 0, "y": 78, "w": 8, "h": 4 },
      "datasource": {
        "type": "grafana-postgresql-datasource",
        "uid": "PCC52D03280B7034C"
      },
      "targets": [
        {
          "datasource": {
            "type": "grafana-postgresql-datasource",
            "uid": "PCC52D03280B7034C"
          },
          "rawSql": "SELECT EXTRACT(EPOCH FROM (NOW() - MAX(finished_at)))::bigint AS seconds_ago FROM scrape_runs WHERE status = 'done'",
          "format": "table",
          "refId": "A"
        }
      ],
      "options": {
        "colorMode": "background",
        "graphMode": "none",
        "textMode": "value_and_name",
        "reduceOptions": { "calcs": ["lastNotNull"] }
      },
      "fieldConfig": {
        "defaults": {
          "unit": "s",
          "displayName": "Last OK scrape",
          "color": { "mode": "thresholds" },
          "thresholds": {
            "mode": "absolute",
            "steps": [
              { "color": "green",  "value": null  },
              { "color": "orange", "value": 7200  },
              { "color": "red",    "value": 21600 }
            ]
          }
        }
      }
    },
    {
      "id": 22,
      "title": "Failed Scrape Runs (24h)",
      "description": "Count of scrape_runs with status='failed' in the last 24 hours.",
      "type": "stat",
      "gridPos": { "x": 8, "y": 78, "w": 8, "h": 4 },
      "datasource": {
        "type": "grafana-postgresql-datasource",
        "uid": "PCC52D03280B7034C"
      },
      "targets": [
        {
          "datasource": {
            "type": "grafana-postgresql-datasource",
            "uid": "PCC52D03280B7034C"
          },
          "rawSql": "SELECT COUNT(*) AS failed FROM scrape_runs WHERE status = 'failed' AND started_at > NOW() - INTERVAL '24 hours'",
          "format": "table",
          "refId": "A"
        }
      ],
      "options": {
        "colorMode": "background",
        "graphMode": "none",
        "textMode": "value_and_name",
        "reduceOptions": { "calcs": ["lastNotNull"] }
      },
      "fieldConfig": {
        "defaults": {
          "displayName": "Failed runs",
          "color": { "mode": "thresholds" },
          "thresholds": {
            "mode": "absolute",
            "steps": [
              { "color": "green",  "value": null },
              { "color": "yellow", "value": 1    },
              { "color": "red",    "value": 3    }
            ]
          }
        }
      }
    },
    {
      "id": 23,
      "title": "Proxy Bandwidth Remaining (MB)",
      "description": "Webshare residential proxy MB left in current billing period. Red <2000 MB.",
      "type": "stat",
      "gridPos": { "x": 16, "y": 78, "w": 8, "h": 4 },
      "datasource": {
        "type": "grafana-postgresql-datasource",
        "uid": "PCC52D03280B7034C"
      },
      "targets": [
        {
          "datasource": {
            "type": "grafana-postgresql-datasource",
            "uid": "PCC52D03280B7034C"
          },
          "rawSql": "SELECT ROUND(bytes_remaining / 1048576.0, 0)::bigint AS mb_remaining FROM proxy_usage_snapshots WHERE bytes_remaining IS NOT NULL ORDER BY captured_at DESC LIMIT 1",
          "format": "table",
          "refId": "A"
        }
      ],
      "options": {
        "colorMode": "background",
        "graphMode": "none",
        "textMode": "value_and_name",
        "reduceOptions": { "calcs": ["lastNotNull"] }
      },
      "fieldConfig": {
        "defaults": {
          "unit": "megabytesSI",
          "displayName": "Proxy MB left",
          "color": { "mode": "thresholds" },
          "thresholds": {
            "mode": "absolute",
            "steps": [
              { "color": "red",    "value": null  },
              { "color": "orange", "value": 2000  },
              { "color": "green",  "value": 10000 }
            ]
          }
        }
      }
    },
    {
      "id": 24,
      "title": "Scraper Runs: Done vs Failed (7d)",
      "description": "Hourly count of completed and failed scrape_run records over the last 7 days.",
      "type": "timeseries",
      "gridPos": { "x": 0, "y": 82, "w": 24, "h": 10 },
      "datasource": {
        "type": "grafana-postgresql-datasource",
        "uid": "PCC52D03280B7034C"
      },
      "targets": [
        {
          "datasource": {
            "type": "grafana-postgresql-datasource",
            "uid": "PCC52D03280B7034C"
          },
          "rawSql": "SELECT date_trunc('hour', started_at) AS time, COUNT(*) AS done FROM scrape_runs WHERE status = 'done' AND started_at > NOW() - INTERVAL '7 days' GROUP BY 1 ORDER BY 1",
          "format": "time_series",
          "refId": "A"
        },
        {
          "datasource": {
            "type": "grafana-postgresql-datasource",
            "uid": "PCC52D03280B7034C"
          },
          "rawSql": "SELECT date_trunc('hour', started_at) AS time, COUNT(*) AS failed FROM scrape_runs WHERE status = 'failed' AND started_at > NOW() - INTERVAL '7 days' GROUP BY 1 ORDER BY 1",
          "format": "time_series",
          "refId": "B"
        }
      ],
      "fieldConfig": {
        "defaults": {
          "custom": { "fillOpacity": 15, "lineWidth": 1 }
        },
        "overrides": [
          {
            "matcher": { "id": "byName", "options": "done" },
            "properties": [
              { "id": "color", "value": { "mode": "fixed", "fixedColor": "green" } },
              { "id": "displayName", "value": "Done" }
            ]
          },
          {
            "matcher": { "id": "byName", "options": "failed" },
            "properties": [
              { "id": "color", "value": { "mode": "fixed", "fixedColor": "red" } },
              { "id": "displayName", "value": "Failed" }
            ]
          }
        ]
      },
      "options": {
        "legend": { "displayMode": "list", "placement": "bottom" }
      }
    }
  ],
  "schemaVersion": 36,
  "version": 8
}
